import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String baseDirectory = "/var/www/data/";

        try {
            String normalizedPath = Paths.get(baseDirectory, userInput).normalize().toString();
            if (!normalizedPath.startsWith(baseDirectory)) {
                System.out.println("Invalid path specified.");
                return;
            }

            File file = new File(normalizedPath);
            FileInputStream fis = new FileInputStream(file);
            byte[] data = new byte[(int) file.length()];
            fis.read(data);
            fis.close();
            System.out.println(new String(data));
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

